func renderSignupForm(title, cta string, listID int) (string, error) {
	const tpl = `<!doctype html>
<form class="sendfox-signup" method="post" action="/api/sendfox/subscribe">
  <h2>{{.Title}}</h2>
  <input type="hidden" name="lists[]" value="{{.ListID}}">
  <label>Email <input required type="email" name="email" autocomplete="email"></label>
  <label>First name <input name="first_name" autocomplete="given-name"></label>
  <button type="submit">{{.CTA}}</button>
</form>
<!-- Server handler: POST https://api.sendfox.com/contacts with Authorization: Bearer $SENDFOX_API_TOKEN and body {email, first_name, lists:[{{.ListID}}]} -->
`
	var b strings.Builder
	err := template.Must(template.New("form").Parse(tpl)).Execute(&b, map[string]any{"Title": title, "CTA": cta, "ListID": listID})
	return b.String(), err
}

func rankListsByObservedMembership(lists, contacts []map[string]any, limit int) []map[string]any {
	counts := map[int]int{}
	for _, ct := range contacts {
		for _, id := range contactListIDs(ct) {
			counts[id]++
		}
	}
	out := make([]map[string]any, 0, len(lists))
	for _, l := range lists {
		id := numericID(l["id"])
		entry := map[string]any{"id": id, "name": l["name"], "observed_contacts": counts[id]}
		out = append(out, entry)
	}
	sort.Slice(out, func(i, j int) bool { return intVal(out[i]["observed_contacts"]) > intVal(out[j]["observed_contacts"]) })
	if limit > 0 && len(out) > limit {
		return out[:limit]
	}
	return out
}

func contactListIDs(ct map[string]any) []int {
	var out []int
	switch v := ct["lists"].(type) {
	case []any:
		for _, item := range v {
			if id := numericID(item); id != 0 {
				out = append(out, id)
			}
		}
	case []int:
		out = append(out, v...)
	}
	return out
}

func firstNMaps(items []map[string]any, n int) []map[string]any {
	if len(items) <= n {
		return items
	}
	return items[:n]
}

func contactsWithoutLists(contacts []map[string]any, limit int) []map[string]any {
	out := []map[string]any{}
	for _, ct := range contacts {
		if len(contactListIDs(ct)) == 0 {
			out = append(out, ct)
			if len(out) >= limit {
				break
			}
		}
	}
	return out
}

func numericID(v any) int {
	switch x := v.(type) {
	case int:
		return x
	case int64:
		return int(x)
	case float64:
		return int(x)
	case string:
		n, _ := strconv.Atoi(x)
		return n
	default:
		return 0
	}
}
func intVal(v any) int {
	if n, ok := v.(int); ok {
		return n
	}
	return numericID(v)
}
